    private function restoreFiles(): void
    {
        $backupRoot = storage_path('backups/reports');
        if (!is_dir($backupRoot)) {
            $this->command?->warn('   Backup directory not found: ' . $backupRoot);
            return;
        }

        $publicDisk = Storage::disk('public');
        $iterator = new \RecursiveIteratorIterator(
            new \RecursiveDirectoryIterator($backupRoot, \RecursiveDirectoryIterator::SKIP_DOTS)
        );

        $count = 0;
        foreach ($iterator as $file) {
            if ($file->isFile()) {
                $relativePath = ltrim(substr($file->getPathname(), strlen($backupRoot)), '\\/');
                $publicDisk->put($relativePath, file_get_contents($file->getPathname()));
                $count++;
            }
        }

        $this->command?->info("   Restored {$count} files to storage/app/public/");
    }
